// Controller state enum
typedef enum {
    CONTROLLER_STATE_SAFE_VENT = 0,
    CONTROLLER_STATE_PRESSURIZING,
    CONTROLLER_STATE_HOLDING,
    CONTROLLER_STATE_RELIEVING,
} controller_state_t;

// Controller state names (for debugging/logging)
#define CONTROLLER_STATE_NAME_SAFE_VENT "STATE SAFE_VENT"
#define CONTROLLER_STATE_NAME_PRESSURIZING "STATE PRESSURIZING"
#define CONTROLLER_STATE_NAME_HOLDING "STATE HOLDING"
#define CONTROLLER_STATE_NAME_RELIEVING "STATE RELIEVING"

// Thresholds
#define CONTROLLER_PRESSURE_LOW_THRESHOLD 40
#define CONTROLLER_PRESSURE_HIGH_THRESHOLD 60
#define CONTROLLER_SENSOR_TIMEOUT_MS 1000U

// Input kinds
typedef enum {
    CONTROLLER_INPUT_NONE = 0,
    CONTROLLER_INPUT_PRESSURE,
    CONTROLLER_INPUT_DOOR_OPEN,
    CONTROLLER_INPUT_DOOR_CLOSED,
    CONTROLLER_INPUT_SENSOR_TIMEOUT,
    CONTROLLER_INPUT_INVALID_PRESSURE,
    CONTROLLER_INPUT_INVALID_DOOR,
} controller_input_kind_t;

// Input structure
typedef struct {
    controller_input_kind_t kind;
    int pressure_kpa;
    bool door_closed;
    uint32_t now_ms;
} controller_input_t;

// Controller state structure
typedef struct {
    bool compressor_on;
    bool vent_open;
    controller_state_t state;
    bool has_valid_pressure;
    int last_pressure_kpa;
    uint32_t last_pressure_ms;
    bool has_valid_door;
    bool door_closed;
    uint32_t last_door_ms;
} controller_t;

// Controller output structure
typedef struct {
    bool compressor_on;
    bool vent_open;
    controller_state_t state;
    const char *state_name;
    bool changed;
    bool timed_out;
} controller_output_t;

arguments.oldText:
#include "controller.h"

// Global state for the controller
static controller_t s_controller = {
    .compressor_on = false,
    .vent_open = true,
    .state = CONTROLLER_STATE_SAFE_VENT,
    .has_valid_pressure = false,
    .last_pressure_kpa = 0,
    .last_pressure_ms = 0U,
    .has_valid_door = false,
    .door_closed = false,
    .last_door_ms = 0U,
};

// Initialize the controller
void controller_init(controller_t *controller)
{
    if (controller == NULL) {
        return;
    }

    // Default state: safe vent-open
    s_controller.compressor_on = false;
    s_controller.vent_open = true;
    s_controller.state = CONTROLLER_STATE_SAFE_VENT;
    s_controller.has_valid_pressure = false;
    s_controller.last_pressure_kpa = 0;
    s_controller.last_pressure_ms = 0U;
    s_controller.has_valid_door = false;
    s_controller.door_closed = false;
    s_controller.last_door_ms = 0U;
}

// Step the controller based on input
controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    if (controller == NULL) {
        return {
            .compressor_on = false,
            .vent_open = true,
            .state = CONTROLLER_STATE_SAFE_VENT,
            .state_name = CONTROLLER_STATE_SAFE_VENT,
            .changed = false,
            .timed_out = false,
        };
    }

    controller_output_t output = {
        .compressor_on = s_controller.compressor_on,
        .vent_open = s_controller.vent_open,
        .state = s_controller.state,
        .state_name = CONTROLLER_STATE_SAFE_VENT,
        .changed = false,
        .timed_out = false,
    };

    bool previous_compressor_on = s_controller.compressor_on;
    bool previous_vent_open = s_controller.vent_open;
    controller_state_t previous_state = s_controller.state;

    // Process the input
    switch (input.kind) {
    case CONTROLLER_INPUT_PRESSURE:
        // Low pressure triggers compression, high pressure releases
        if (input.pressure_kpa < CONTROLLER_PRESSURE_LOW_THRESHOLD) {
            output.compressor_on = true;
            output.vent_open = false;
            s_controller.state = CONTROLLER_STATE_PRESSURIZING;
            output.state_name = CONTROLLER_STATE_PRESSURIZING;
        } else if (input.pressure_kpa > CONTROLLER_PRESSURE_HIGH_THRESHOLD) {
            output.compressor_on = false;
            output.vent_open = true;
            s_controller.state = CONTROLLER_STATE_RELIEVING;
            output.state_name = CONTROLLER_STATE_RELIEVING;
        } else {
            // In the 40-60 band, hold previous safe output
            if (previous_compressor_on != output.compressor_on) {
                output.changed = true;
            }
            if (previous_vent_open != output.vent_open) {
                output.changed = true;
            }
            s_controller.state = previous_state;
            output.state_name = CONTROLLER_STATE_HOLDING;
        }
        break;

    case CONTROLLER_INPUT_DOOR_OPEN:
        // Door open forces safe vent-open state
        output.compressor_on = false;
        output.vent_open = true;
        s_controller.state = CONTROLLER_STATE_SAFE_VENT;
        output.state_name = CONTROLLER_STATE_SAFE_VENT;
        break;

    case CONTROLLER_INPUT_DOOR_CLOSED:
        // Door closed: check pressure band
        if (input.pressure_kpa < CONTROLLER_PRESSURE_LOW_THRESHOLD) {
            // Low pressure with door closed: compress and vent closed
            output.compressor_on = true;
            output.vent_open = false;
            s_controller.state = CONTROLLER_STATE_PRESSURIZING;
            output.state_name = CONTROLLER_STATE_PRESSURIZING;
        } else if (input.pressure_kpa > CONTROLLER_PRESSURE_HIGH_THRESHOLD) {
            // High pressure with door closed: vent open
            output.compressor_on = false;
            output.vent_open = true;
            s_controller.state = CONTROLLER_STATE_RELIEVING;
            output.state_name = CONTROLLER_STATE_RELIEVING;
        } else {
            // Pressure in 40-60 band: hold previous safe output
            if (previous_compressor_on != output.compressor_on) {
                output.changed = true;
            }
            if (previous_vent_open != output.vent_open) {
                output.changed = true;
            }
            s_controller.state = previous_state;
            output.state_name = CONTROLLER_STATE_HOLDING;
        }
        break;

    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
    case CONTROLLER_INPUT_INVALID_PRESSURE:
    case CONTROLLER_INPUT_INVALID_DOOR:
        // Timeout or invalid input forces safe vent-open
        output.compressor_on = false;
        output.vent_open = true;
        s_controller.state = CONTROLLER_STATE_SAFE_VENT;
        output.state_name = CONTROLLER_STATE_SAFE_VENT;
        break;

    case CONTROLLER_INPUT_NONE:
    default:
        // No input, hold previous state
        if (previous_compressor_on != output.compressor_on) {
            output.changed = true;
        }
        if (previous_vent_open != output.vent_open) {
            output.changed = true;
        }
        s_controller.state = previous_state;
        output.state_name = CONTROLLER_STATE_HOLDING;
        break;
    }

    // Check for timeout condition: either sensor stale for more than 1000ms
    if (s_controller.has_valid_pressure && input.now_ms - s_controller.last_pressure_ms > CONTROLLER_SENSOR_TIMEOUT_MS) {
        output.compressor_on = false;
        output.vent_open = true;
        s_controller.state = CONTROLLER_STATE_SAFE_VENT;
        output.state_name = CONTROLLER_STATE_SAFE_VENT;
    }

    if (s_controller.has_valid_door && input.now_ms - s_controller.last_door_ms > CONTROLLER_SENSOR_TIMEOUT_MS) {
        output.compressor_on = false;
        output.vent_open = true;
        s_controller.state = CONTROLLER_STATE_SAFE_VENT;
        output.state_name = CONTROLLER_STATE_SAFE_VENT;
    }

    // Check if any state changed
    if (output.changed || input.kind != CONTROLLER_INPUT_NONE) {
        output.timed_out = false;  // Reset timeout flag on change
    }

    return output;
}

// Get state name for a given state
const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_SAFE_VENT:
        return CONTROLLER_STATE_SAFE_VENT;
    case CONTROLLER_STATE_PRESSURIZING:
        return CONTROLLER_STATE_PRESSURIZING;
    case CONTROLLER_STATE_HOLDING:
        return CONTROLLER_STATE_HOLDING;
    case CONTROLLER_STATE_RELIEVING:
        return CONTROLLER_STATE_RELIEVING;
    default:
        return CONTROLLER_STATE_SAFE_VENT;
    }
}

arguments.newText:
#include "controller.h"

// Global state for the controller
static controller_t s_controller = {
    .compressor_on = false,
    .vent_open = true,
    .state = CONTROLLER_STATE_SAFE_VENT,
    .has_valid_pressure = false,
    .last_pressure_kpa = 0,
    .last_pressure_ms = 0U,
    .has_valid_door = false,
    .door_closed = false,
    .last_door_ms = 0U,
};

// Initialize the controller
void controller_init(controller_t *controller)
{
    if (controller == NULL) {
        return;
    }

    // Default state: safe vent-open
    s_controller.compressor_on = false;
    s_controller.vent_open = true;
    s_controller.state = CONTROLLER_STATE_SAFE_VENT;
    s_controller.has_valid_pressure = false;
    s_controller.last_pressure_kpa = 0;
    s_controller.last_pressure_ms = 0U;
    s_controller.has_valid_door = false;
    s_controller.door_closed = false;
    s_controller.last_door_ms = 0U;
}

// Step the controller based on input
controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    if (controller == NULL) {
        return (controller_output_t){
            .compressor_on = false,
            .vent_open = true,
            .state = CONTROLLER_STATE_SAFE_VENT,
            .state_name = CONTROLLER_STATE_NAME_SAFE_VENT,
            .changed = false,
            .timed_out = false,
        };
    }

    controller_output_t output;
    bool previous_compressor_on = s_controller.compressor_on;
    bool previous_vent_open = s_controller.vent_open;
    controller_state_t previous_state = s_controller.state;

    // Initialize output with current state
    output.compressor_on = s_controller.compressor_on;
    output.vent_open = s_controller.vent_open;
    output.state = s_controller.state;
    output.state_name = CONTROLLER_STATE_NAME_SAFE_VENT;  // Will be updated below
    output.changed = false;
    output.timed_out = false;

    // Check for timeout FIRST (before processing new input)
    bool timed_out = false;
    if ((s_controller.has_valid_pressure && input.now_ms - s_controller.last_pressure_ms > CONTROLLER_SENSOR_TIMEOUT_MS) ||
        (s_controller.has_valid_door && input.now_ms - s_controller.last_door_ms > CONTROLLER_SENSOR_TIMEOUT_MS)) {
        timed_out = true;
        // Force safe vent state on timeout
        s_controller.compressor_on = false;
        s_controller.vent_open = true;
        s_controller.state = CONTROLLER_STATE_SAFE_VENT;
    }

    if (timed_out) {
        output.compressor_on = false;
        output.vent_open = true;
        output.state = CONTROLLER_STATE_SAFE_VENT;
        output.state_name = CONTROLLER_STATE_NAME_SAFE_VENT;
        output.timed_out = true;
        return output;
    }

    // Process the input based on kind
    switch (input.kind) {
    case CONTROLLER_INPUT_PRESSURE:
        // Update pressure freshness
        s_controller.has_valid_pressure = true;
        s_controller.last_pressure_kpa = input.pressure_kpa;
        s_controller.last_pressure_ms = input.now_ms;

        if (s_controller.has_valid_door) {
            // Door closed and we have valid pressure
            if (!s_controller.door_closed) {
                // This shouldn't happen - door should be closed if has_valid_door is true
                break;
            }

            if (input.pressure_kpa < CONTROLLER_PRESSURE_LOW_THRESHOLD) {
                // Low pressure: pressurize
                s_controller.compressor_on = true;
                s_controller.vent_open = false;
                s_controller.state = CONTROLLER_STATE_PRESSURIZING;
                output.compressor_on = true;
                output.vent_open = false;
                output.state = CONTROLLER_STATE_PRESSURIZING;
                output.state_name = CONTROLLER_STATE_NAME_PRESSURIZING;
                output.changed = true;
            } else if (input.pressure_kpa > CONTROLLER_PRESSURE_HIGH_THRESHOLD) {
                // High pressure: relieve
                s_controller.compressor_on = false;
                s_controller.vent_open = true;
                s_controller.state = CONTROLLER_STATE_RELIEVING;
                output.compressor_on = false;
                output.vent_open = true;
                output.state = CONTROLLER_STATE_RELIEVING;
                output.state_name = CONTROLLER_STATE_NAME_RELIEVING;
                output.changed = true;
            } else {
                // In the 40-60 band: hold previous state
                s_controller.state = previous_state;
                output.state = s_controller.state;
                output.state_name = CONTROLLER_STATE_NAME_HOLDING;
                if (output.compressor_on != previous_compressor_on) {
                    output.changed = true;
                }
                if (output.vent_open != previous_vent_open) {
                    output.changed = true;
                }
            }
        } else {
            // No valid door state - stay in safe vent
            s_controller.state = CONTROLLER_STATE_SAFE_VENT;
            output.compressor_on = false;
            output.vent_open = true;
            output.state = CONTROLLER_STATE_SAFE_VENT;
            output.state_name = CONTROLLER_STATE_NAME_SAFE_VENT;
        }
        break;

    case CONTROLLER_INPUT_DOOR_OPEN:
        // Door open forces safe vent-open state
        s_controller.compressor_on = false;
        s_controller.vent_open = true;
        s_controller.state = CONTROLLER_STATE_SAFE_VENT;
        s_controller.has_valid_door = true;
        s_controller.door_closed = false;
        s_controller.last_door_ms = input.now_ms;

        output.compressor_on = false;
        output.vent_open = true;
        output.state = CONTROLLER_STATE_SAFE_VENT;
        output.state_name = CONTROLLER_STATE_NAME_SAFE_VENT;
        output.changed = true;
        break;

    case CONTROLLER_INPUT_DOOR_CLOSED:
        // Door closed - check pressure
        s_controller.has_valid_door = true;
        s_controller.door_closed = true;
        s_controller.last_door_ms = input.now_ms;

        if (s_controller.has_valid_pressure) {
            if (input.pressure_kpa < CONTROLLER_PRESSURE_LOW_THRESHOLD) {
                // Low pressure: pressurize
                s_controller.compressor_on = true;
                s_controller.vent_open = false;
                s_controller.state = CONTROLLER_STATE_PRESSURIZING;
                output.compressor_on = true;
                output.vent_open = false;
                output.state = CONTROLLER_STATE_PRESSURIZING;
                output.state_name = CONTROLLER_STATE_NAME_PRESSURIZING;
                output.changed = true;
            } else if (input.pressure_kpa > CONTROLLER_PRESSURE_HIGH_THRESHOLD) {
                // High pressure: relieve
                s_controller.compressor_on = false;
                s_controller.vent_open = true;
                s_controller.state = CONTROLLER_STATE_RELIEVING;
                output.compressor_on = false;
                output.vent_open = true;
                output.state = CONTROLLER_STATE_RELIEVING;
                output.state_name = CONTROLLER_STATE_NAME_RELIEVING;
                output.changed = true;
            } else {
                // In the 40-60 band: hold previous state
                s_controller.state = previous_state;
                output.compressor_on = s_controller.compressor_on;
                output.vent_open = s_controller.vent_open;
                output.state = s_controller.state;
                output.state_name = CONTROLLER_STATE_NAME_HOLDING;
                if (output.compressor_on != previous_compressor_on) {
                    output.changed = true;
                }
                if (output.vent_open != previous_vent_open) {
                    output.changed = true;
                }
            }
        } else {
            // No valid pressure - stay in safe vent
            s_controller.compressor_on = false;
            s_controller.vent_open = true;
            s_controller.state = CONTROLLER_STATE_SAFE_VENT;
            output.compressor_on = false;
            output.vent_open = true;
            output.state = CONTROLLER_STATE_SAFE_VENT;
            output.state_name = CONTROLLER_STATE_NAME_SAFE_VENT;
        }
        break;

    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
    case CONTROLLER_INPUT_INVALID_PRESSURE:
    case CONTROLLER_INPUT_INVALID_DOOR:
        // Timeout or invalid input forces safe vent-open
        s_controller.compressor_on = false;
        s_controller.vent_open = true;
        s_controller.state = CONTROLLER_STATE_SAFE_VENT;

        output.compressor_on = false;
        output.vent_open = true;
        output.state = CONTROLLER_STATE_SAFE_VENT;
        output.state_name = CONTROLLER_STATE_NAME_SAFE_VENT;
        output.timed_out = true;
        break;

    case CONTROLLER_INPUT_NONE:
    default:
        // No input - hold current state (no changes to freshness)
        s_controller.state = previous_state;
        output.compressor_on = s_controller.compressor_on;
        output.vent_open = s_controller.vent_open;
        output.state = s_controller.state;
        output.state_name = CONTROLLER_STATE_NAME_HOLDING;
        break;
    }

    // Update state name
    if (output.state == CONTROLLER_STATE_SAFE_VENT) {
        output.state_name = CONTROLLER_STATE_NAME_SAFE_VENT;
    } else if (output.state == CONTROLLER_STATE_PRESSURIZING) {
        output.state_name = CONTROLLER_STATE_NAME_PRESSURIZING;
    } else if (output.state == CONTROLLER_STATE_HOLDING) {
        output.state_name = CONTROLLER_STATE_NAME_HOLDING;
    } else if (output.state == CONTROLLER_STATE_RELIEVING) {
        output.state_name = CONTROLLER_STATE_NAME_RELIEVING;
    }

    return output;
}

// Get state name for a given state
const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_SAFE_VENT:
        return CONTROLLER_STATE_NAME_SAFE_VENT;
    case CONTROLLER_STATE_PRESSURIZING:
        return CONTROLLER_STATE_NAME_PRESSURIZING;
    case CONTROLLER_STATE_HOLDING:
        return CONTROLLER_STATE_NAME_HOLDING;
    case CONTROLLER_STATE_RELIEVING:
        return CONTROLLER_STATE_NAME_RELIEVING;
    default:
        return CONTROLLER_STATE_NAME_SAFE_VENT;
    }
}

