static void transport_handle_received_line(const char *line)
{
    ESP_LOGI(TAG, "RX: %s", line);

    protocol_input_t input = {
        .kind = PROTOCOL_INPUT_NONE,
        .pressure_kpa = 0,
        .door_closed = false,
    };

    protocol_parse_result_t result = protocol_parse_line(line, &input);
    ESP_LOGI(TAG, "PARSE: %s kind=%d", line, (int)result);

    if (result == PROTOCOL_PARSE_IGNORED) {
        // Malformed input forces safe vent-open state
        controller_input_t timeout_input = {
            .kind = CONTROLLER_INPUT_SENSOR_TIMEOUT,
            .pressure_kpa = 0,
            .door_closed = false,
            .now_ms = transport_now_ms(),
        };
        controller_output_t output = controller_step(&s_transport_context.controller, timeout_input);
        ESP_LOGI(TAG, "MALFORMED: changed=%d state=%s", (int)output.changed, output.state_name);
        if (output.changed) {
            transport_send_actuators(output.compressor_on, output.vent_open);
            transport_send_debug(output.state_name);
        }
        return;
    }

    ESP_LOGI(TAG, "APPLY: kind=%d pressure=%d door=%d", (int)input.kind, input.pressure_kpa, input.door_closed);
    transport_apply_protocol_input(&input);
}

